    supabaseUrl: POPDAM_SUPABASE_URL,
    supabaseAnonKey: POPDAM_ANON_KEY,
  },
} as const;

export const APP_MODE: AppMode = detectMode();
export const CURRENT_APP = APP_CONFIG[APP_MODE];
